            },
            dailyUsage: { ...defaultUserData.dailyUsage, ...(data.dailyUsage || {}) },
            weeklyUsage: { ...defaultUserData.weeklyUsage, ...(data.weeklyUsage || {}) },
        };
    };

    useEffect(() => {
        try {
            const savedData = localStorage.getItem('nutribot-userdata');
