import { GoogleGenAI, Part } from "@google/genai";
import { DailyPlan, Meal, UserData, MacroData, Recipe, FoodItem } from '../types';
import { sanitizeRecipe, sanitizeDailyPlan } from "../components/utils/sanitizers";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

function buildUserProfile(userData: UserData): string {
    const diets = userData.dietaryPreferences?.diets?.join(', ') || 'Nenhuma';
    const restrictions = userData.dietaryPreferences?.restrictions?.join(', ') || 'Nenhuma';

    return `PERFIL:
    - Idade/Gênero: ${userData.age} anos, ${userData.gender}
    - Peso/Meta: ${userData.weight}kg -> ${userData.weightGoal}kg
    - Dietas: ${diets}
    - Restrições: ${restrictions}
    - Macros Alvo: Calorias ${userData.macros.calories.goal}, Proteína ${userData.macros.protein.goal}g`;
}

/**
 * Função robusta para extrair JSON de texto com Markdown ou sujo.
 */
async function generateJson<T>(prompt: string | { parts: Part[] }, model: string = 'gemini-2.5-flash'): Promise<T> {
    try {
        const response = await ai.models.generateContent({
            model,
            contents: prompt,
            config: { 
                responseMimeType: "application/json",
            }
        });

        const text = response.text || "{}";

        // 1. Tenta extrair apenas o bloco JSON usando Regex (pega o primeiro { ... } ou [ ... ])
        // Isso ignora textos introdutórios como "Aqui está o seu JSON:"
        const jsonMatch = text.match(/(\{[\s\S]*\}|\[[\s\S]*\])/);
        let jsonString = jsonMatch ? jsonMatch[0] : text;

        // 2. Limpeza adicional caso o Regex tenha pego algo sujo (ex: markdown residuals)
        jsonString = jsonString.replace(/```json/g, '').replace(/```/g, '').trim();

        return JSON.parse(jsonString) as T;
    } catch (error) {
        console.error("Gemini JSON Error:", error);
        // Retorna um objeto vazio ou array vazio dependendo do contexto para não quebrar a app,
        // mas idealmente deveria lançar para o frontend tratar.
        throw new Error("Erro ao processar resposta da IA. Tente novamente.");
    }
}

