        protein: 'N/A',
        carbs: 'N/A',
        fat: 'N/A'
    };

    // 2. Proteção contra null/undefined ou tipos errados
    if (!recipe || typeof recipe !== 'object') {
        return {
            id: `error-${Date.now()}`,
            title: 'Erro ao carregar receita',
            description: 'Dados inválidos recebidos.',
            prepTime: '-',
            difficulty: 'Fácil',
            servings: '-',
            ingredients: [],
            instructions: [],
            nutritionalInfo: fallbackInfo,
            imagePrompt: ''
        };
    }

    // 3. Extração segura de informações nutricionais
    // Tenta encontrar em diferentes propriedades e garante que seja um objeto
    let rawInfo = recipe.nutritionalInfo || recipe.macros || {};
    if (typeof rawInfo !== 'object') rawInfo = {};

    // Usa recipe.calories diretamente como fallback se rawInfo estiver vazio
    const safeNutritionalInfo: NutritionalInfo = {
        calories: safeString(rawInfo.calories || recipe.calories),
        protein: safeString(rawInfo.protein || recipe.protein),
        carbs: safeString(rawInfo.carbs || recipe.carbohydrates || recipe.carbs),
        fat: safeString(rawInfo.fat || recipe.fat)
    };

    // 4. Construção do objeto final garantido
    return {
        id: safeString(recipe.id, `gen-${Math.random().toString(36).substr(2, 9)}`),
        title: safeString(recipe.title, 'Receita Sem Título'),
        description: safeString(recipe.description, ''),
        prepTime: safeString(recipe.prepTime, 'N/A'),
        difficulty: (['Fácil', 'Médio', 'Difícil'].includes(recipe.difficulty) ? recipe.difficulty : 'Fácil') as any,
        servings: safeString(recipe.servings, '1 porção'),
        ingredients: Array.isArray(recipe.ingredients) ? recipe.ingredients.map((i: any) => safeString(i)) : [],
        instructions: Array.isArray(recipe.instructions) ? recipe.instructions.map((i: any) => safeString(i)) : [],
        nutritionalInfo: safeNutritionalInfo,
        imagePrompt: safeString(recipe.imagePrompt, `Foto profissional de ${recipe.title || 'comida'}`),
        generatedImage: recipe.generatedImage
    };
};

Compreendo perfeitamente a frustração. O problema de "incompatibilidade e bugs" na IA ocorre principalmente porque o modelo de linguagem (Gemini) nem sempre retorna o JSON exatamente como o código espera (às vezes ele adiciona texto antes, esquece chaves, ou aninha os dados incorretamente), e o frontend tenta usar esses dados "sujos" diretamente.

Vou corrigir toda a camada de integração da IA para implementar um padrão de **"Zero Trust" (Confiança Zero)**. Isso significa:

1.  **Extração Cirúrgica de JSON:** O serviço não vai mais "tentar" ler a resposta. Ele vai usar Regex (Expressões Regulares) para arrancar o objeto JSON válido de dentro da resposta da IA, ignorando qualquer texto introdutório.
2.  **Prompts Blindados:** Vou reescrever os prompts para serem extremamente literais sobre a estrutura de dados (tipos, nomes de campos).
3.  **Sanitização na Entrada:** O componente de Receitas e o App principal irão passar *todos* os dados recebidos da API pela função de limpeza (`sanitizeRecipe`, `sanitizeDailyPlan`) *antes* de salvar no estado.

Aqui estão as correções definitivas:

