                        <div className="text-center text-slate-400 p-10 bg-white rounded-2xl border border-gray-100">
                            <BookOpenIcon className="w-16 h-16 mx-auto mb-4" />
                            <p className="font-semibold">As receitas encontradas aparecerão aqui</p>
                            <p className="text-sm">Use o campo de busca para começar a explorar.</p>
                        </div>
                    )}
                </div>
                </>
            )}

            {/* ... (Favorites tab content remains the same) */}
            {activeTab === 'favorites' && (
                 <div className="min-h-[400px]">
                    {favoriteRecipes.length > 0 ? (
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                             {favoriteRecipes.map(recipe => <RecipeCard key={recipe.id} recipe={recipe} isFavorite />)}
                        </div>
                    ) : (
                        <div className="text-center text-slate-400 p-10 bg-white rounded-2xl border border-gray-100">
                            <StarIcon className="w-16 h-16 mx-auto mb-4 text-slate-300" />
                            <p className="font-semibold">Nenhuma receita favorita ainda</p>
                            <p className="text-sm">Clique na estrela de uma receita para salvá-la aqui.</p>
                        </div>
                    )}
                 </div>
            )}

            {displayRecipe && (
                <Modal isOpen={!!displayRecipe} onClose={() => setSelectedRecipe(null)} title={displayRecipe.title} size="4xl">
                    <div className="absolute top-[0.875rem] right-16 z-10">
                         <button onClick={handleFavoriteClick} className="p-2 rounded-full hover:bg-yellow-100 transition-colors" aria-label="Favoritar receita">
                            <StarIcon className={`w-6 h-6 ${favoriteRecipes.some(r => r.id === displayRecipe.id) ? 'text-yellow-400 fill-current' : 'text-gray-400'}`} />
                        </button>
                    </div>
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                        <div>
                             <div className="aspect-square bg-slate-100 rounded-lg mb-6 flex items-center justify-center overflow-hidden relative group">
                                {isImageLoading ? (
                                    <div className="text-center text-slate-500">
                                        <LoadingSpinner className="w-10 h-10 mx-auto mb-2" />
                                        <p className="text-sm font-semibold">Gerando imagem...</p>
                                    </div>
                                ) : recipeImageCache[displayRecipe.id] ? (
                                    <>
                                        <img src={recipeImageCache[displayRecipe.id]} alt={displayRecipe.title} className="w-full h-full object-cover"/>
                                        <div className="absolute bottom-4 right-4">
                                            <button onClick={handleShareRecipe} className="bg-slate-900/70 backdrop-blur-sm text-white font-semibold py-2 px-4 rounded-lg flex items-center justify-center gap-2 text-sm transition-all hover:bg-slate-900 shadow-lg">
                                               <ShareIcon className="w-4 h-4"/> Compartilhar Receita
                                            </button>
                                        </div>
                                    </>
                                ) : (
                                    <div className="text-center p-4">
                                        <ImageIcon className="w-16 h-16 text-slate-300 mx-auto mb-4" />
                                        <button onClick={handleGenerateImage} className="bg-slate-800 hover:bg-slate-900 text-white font-semibold py-2 px-4 rounded-lg flex items-center justify-center gap-2 text-sm transition-colors">
                                           <SparklesIcon className="w-4 h-4"/> Gerar imagem com IA
                                        </button>
                                        {imageGenUses.limit !== Infinity && ( 
                                            <p className="text-xs text-slate-400 mt-2">
                                                Gerações de imagem restantes: <strong>{imageGenUses.remaining} / {imageGenUses.limit}</strong>
                                            </p>
                                        )}
                                    </div>
                                )}
                            </div>
                            <h3 className="font-bold text-slate-800 text-lg mb-3">Informação Nutricional (por porção)</h3>
                             {/* Defensive rendering with optional chaining and fallback */}
                             <div className="grid grid-cols-2 gap-3 text-sm">
                                <p className="text-slate-600">Calorias: <strong className="font-semibold text-slate-800">{displayRecipe.nutritionalInfo?.calories || 'N/A'}</strong></p>
                                <p className="text-slate-600">Proteínas: <strong className="font-semibold text-slate-800">{displayRecipe.nutritionalInfo?.protein || 'N/A'}</strong></p>
                                <p className="text-slate-600">Carboidratos: <strong className="font-semibold text-slate-800">{displayRecipe.nutritionalInfo?.carbs || 'N/A'}</strong></p>
                                <p className="text-slate-600">Gorduras: <strong className="font-semibold text-slate-800">{displayRecipe.nutritionalInfo?.fat || 'N/A'}</strong></p>
                             </div>
                        </div>
                        <div>
                             <p className="text-slate-600 mb-6">{displayRecipe.description}</p>
                             <div className="flex gap-6 text-sm mb-6 border-y border-gray-200 py-3">
                                <div className="flex items-center gap-2 text-slate-600"><ClockIcon className="w-5 h-5 text-brand-green"/> <span className="font-semibold text-slate-800">{displayRecipe.prepTime}</span></div>
                                <div className="flex items-center gap-2 text-slate-600"><BarChartIcon className="w-5 h-5 text-brand-blue"/> <span className="font-semibold text-slate-800">{displayRecipe.difficulty}</span></div>
                                <div className="flex items-center gap-2 text-slate-600"><UsersIcon className="w-5 h-5 text-brand-orange"/> <span className="font-semibold text-slate-800">{displayRecipe.servings}</span></div>
                             </div>

                             <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                <div>
                                    <h3 className="font-bold text-slate-800 text-lg mb-3">Ingredientes</h3>
                                    <ul className="space-y-1.5 text-slate-600 list-disc list-inside">
                                        {displayRecipe.ingredients.map((ing, i) => <li key={i}>{ing}</li>)}
                                    </ul>
                                </div>
                                <div>
                                    <h3 className="font-bold text-slate-800 text-lg mb-3">Modo de Preparo</h3>
                                    <ol className="space-y-2 text-slate-600 list-decimal list-inside">
                                        {displayRecipe.instructions.map((inst, i) => <li key={i}>{inst}</li>)}
                                    </ol>
                                </div>
                             </div>
                        </div>
                    </div>
                </Modal>
            )}
        </div>
    );
};

export default RecipesView;
